import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Weather icon mapping helper
const getWeatherIcon = (condition: string): string => {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloud')) return '☁️';
  if (normalized.includes('rain')) return '🌧️';
  if (normalized.includes('snow')) return '❄️';
  if (normalized.includes('wind')) return '💨';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('fog') || normalized.includes('mist')) return '🌫️';
  return '🌤️';
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main Weather Card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* City and Condition Header */}
            <Stack direction="horizontal" justify="between" align="center">
              <Stack gap="var(--ggui-spacing-2)" align="start">
                <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
              </Stack>
              <Text style={{ fontSize: '4rem' }}>{getWeatherIcon(props.condition)}</Text>
            </Stack>

            <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

            {/* Temperature Display - Large and Prominent */}
            <Stack gap="var(--ggui-spacing-1)" align="center" justify="center">
              <Text
                style={{
                  fontSize: '5rem',
                  fontWeight: 'bold',
                  color: 'var(--ggui-color-primary-600)',
                  lineHeight: 1,
                }}
              >
                {props.temperature}°
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                {props.unit === 'C' ? 'Celsius' : 'Fahrenheit'}
              </Text>
            </Stack>

            <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

            {/* Humidity and Wind Speed Grid */}
            <Row gap="var(--ggui-spacing-4)" justify="between" align="stretch">
              {/* Humidity Card */}
              <Box
                padding="var(--ggui-spacing-4)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-md)"
                style={{ flex: 1 }}
              >
                <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                  <Icon name="droplets" size={24} color="var(--ggui-color-primary-600)" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" align="center">
                    Humidity
                  </Text>
                  <Text
                    style={{
                      fontSize: 'var(--ggui-font-size-2xl)',
                      fontWeight: 'bold',
                      color: 'var(--ggui-color-onSurface)',
                    }}
                    align="center"
                  >
                    {props.humidity}%
                  </Text>
                </Stack>
              </Box>

              {/* Wind Speed Card */}
              <Box
                padding="var(--ggui-spacing-4)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-md)"
                style={{ flex: 1 }}
              >
                <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                  <Icon name="wind" size={24} color="var(--ggui-color-primary-600)" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" align="center">
                    Wind Speed
                  </Text>
                  <Text
                    style={{
                      fontSize: 'var(--ggui-font-size-2xl)',
                      fontWeight: 'bold',
                      color: 'var(--ggui-color-onSurface)',
                    }}
                    align="center"
                  >
                    {props.windSpeed} km/h
                  </Text>
                </Stack>
              </Box>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast Strip */}
        {props.forecast && props.forecast.length > 0 && (
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
            <Row gap="var(--ggui-spacing-2)" align="stretch" wrap>
              {props.forecast.map((day, index) => (
                <Card
                  key={index}
                  padding="var(--ggui-spacing-4)"
                  shadow="sm"
                  radius="md"
                  style={{
                    flex: '1 1 150px',
                    minWidth: '140px',
                    textAlign: 'center',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                    {/* Day Name */}
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      {day.day || `Day ${index + 1}`}
                    </Text>

                    {/* Weather Icon */}
                    <Text style={{ fontSize: '2rem' }}>
                      {day.icon || getWeatherIcon(day.day || '')}
                    </Text>

                    {/* High/Low Temps */}
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2)" justify="center">
                      <Text
                        style={{
                          fontSize: 'var(--ggui-font-size-sm)',
                          fontWeight: 'bold',
                          color: 'var(--ggui-color-primary-600)',
                        }}
                      >
                        {day.high !== undefined ? `${day.high}°` : 'N/A'}
                      </Text>
                      <Text
                        style={{
                          fontSize: 'var(--ggui-font-size-sm)',
                          color: 'var(--ggui-color-onSurfaceVariant)',
                        }}
                      >
                        {day.low !== undefined ? `${day.low}°` : 'N/A'}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              ))}
            </Row>
          </Stack>
        )}
      </Stack>
    </Container>
  );
}

