// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Priority badge color mapping
const getPriorityVariant = (priority?: string): 'default' | 'primary' | 'success' | 'warning' | 'error' | 'info' => {
  switch (priority) {
    case 'high': return 'error';
    case 'medium': return 'warning';
    case 'low': return 'success';
    default: return 'default';
  }
};

// Task card sub-component
function TaskCard({ task, columns, onMove, onEdit }: { task: any; columns: any[] | undefined; onMove: (taskId: string, columnId: string) => void; onEdit: (task: any) => void }) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');
  const [editPriority, setEditPriority] = useState(task.priority || 'medium');
  const [editAssignee, setEditAssignee] = useState(task.assignee || '');
  const [editDueDate, setEditDueDate] = useState(task.dueDate || '');
  const [showMoveMenu, setShowMoveMenu] = useState(false);

  const handleMoveClick = (columnId: string) => {
    onMove(task.id, columnId);
    setShowMoveMenu(false);
  };

  const handleSaveEdit = () => {
    onEdit({ ...task, title: editTitle, priority: editPriority, assignee: editAssignee, dueDate: editDueDate });
    setIsEditing(false);
  };

  if (isEditing) {
    return (
      <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md">
        <Stack gap="var(--ggui-spacing-2)">
          <Input
            label="Task title"
            value={editTitle}
            onChange={setEditTitle}
            size="sm"
          />
          <Select
            label="Priority"
            value={editPriority}
            onChange={setEditPriority}
            options={[
              { value: 'low', label: 'Low' },
              { value: 'medium', label: 'Medium' },
              { value: 'high', label: 'High' },
            ]}
            size="sm"
          />
          <Input
            label="Assignee"
            value={editAssignee}
            onChange={setEditAssignee}
            placeholder="Initials (e.g., JD)"
            size="sm"
          />
          <Input
            label="Due Date"
            value={editDueDate}
            onChange={setEditDueDate}
            placeholder="YYYY-MM-DD"
            type="text"
            size="sm"
          />
          <Row gap="var(--ggui-spacing-2)" justify="end">
            <Button variant="ghost" size="sm" onClick={() => { setIsEditing(false); setEditTitle(task.title || ''); setEditPriority(task.priority || 'medium'); setEditAssignee(task.assignee || ''); setEditDueDate(task.dueDate || ''); }}>
              Cancel
            </Button>
            <Button variant="primary" size="sm" onClick={handleSaveEdit}>
              Save
            </Button>
          </Row>
        </Stack>
      </Card>
    );
  }

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        <Row justify="between" align="start">
          <Stack gap="var(--ggui-spacing-1)" style={{ flex: 1 }}>
            <Text variant="body" weight="medium" onClick={() => setIsEditing(true)} as={Clickable} style={{ cursor: 'pointer' }}>
              {task.title || 'Untitled Task'}
            </Text>
            {task.dueDate && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                📅 {task.dueDate}
              </Text>
            )}
          </Stack>
          <Row gap="var(--ggui-spacing-2)" align="center">
            {task.priority && (
              <Badge variant={getPriorityVariant(task.priority)} size="sm">
                {task.priority}
              </Badge>
            )}
            <Button variant="ghost" size="sm" leftIcon={<Icon name="edit" />} onClick={() => setIsEditing(true)} />
          </Row>
        </Row>
        <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
          {task.assignee && (
            <Avatar name={task.assignee} size="sm" shape="circle" />
          )}
          <Dropdown
            trigger={<Button variant="ghost" size="sm">Move</Button>}
            options={columns && columns.length > 0
              ? columns.filter((c) => c.id !== task.column).map((c) => ({ value: c.id || '', label: c.name || '' }))
              : []}
            value=""
            onChange={(columnId) => handleMoveClick(columnId)}
            placement="bottom-end"
          />
        </Row>
      </Stack>
    </Card>
  );
}

// Column component
function KanbanColumn({ column, tasks, columns, onMove, onEdit, onAddTask }: { column: any; tasks: any[]; columns: any[]; onMove: (taskId: string, columnId: string) => void; onEdit: (task: any) => void; onAddTask: (title: string, priority: string) => void }) {
  const [showAddForm, setShowAddForm] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('medium');

  const columnTasks = tasks.filter((t) => t.column === column.id);

  const handleAdd = () => {
    if (newTaskTitle.trim()) {
      onAddTask(newTaskTitle, newTaskPriority);
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setShowAddForm(false);
    }
  };

  return (
    <Card shadow="md" padding="var(--ggui-spacing-4)" radius="lg" style={{ minWidth: '300px', minHeight: '400px', display: 'flex', flexDirection: 'column' }}>
      <Stack gap="var(--ggui-spacing-3)" style={{ flex: 1 }}>
        <Row justify="between" align="center">
          <Heading level={3}>{column.name}</Heading>
          <Badge variant="default" size="sm">{columnTasks.length}</Badge>
        </Row>
        <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
        <Stack gap="var(--ggui-spacing-2)" style={{ flex: 1, overflowY: 'auto' }}>
          {columnTasks.map((task) => (
            <TaskCard
              key={task.id}
              task={task}
              columns={columns}
              onMove={onMove}
              onEdit={onEdit}
            />
          ))}
        </Stack>
        <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
        {showAddForm ? (
          <Stack gap="var(--ggui-spacing-2)">
            <Input
              label="Task title"
              value={newTaskTitle}
              onChange={setNewTaskTitle}
              placeholder="Enter task title"
              size="sm"
            />
            <Select
              label="Priority"
              value={newTaskPriority}
              onChange={setNewTaskPriority}
              options={[
                { value: 'low', label: 'Low' },
                { value: 'medium', label: 'Medium' },
                { value: 'high', label: 'High' },
              ]}
              size="sm"
            />
            <Row gap="var(--ggui-spacing-2)" justify="end">
              <Button
                variant="ghost"
                size="sm"
                onClick={() => {
                  setShowAddForm(false);
                  setNewTaskTitle('');
                  setNewTaskPriority('medium');
                }}
              >
                Cancel
              </Button>
              <Button variant="primary" size="sm" onClick={handleAdd}>
                Add
              </Button>
            </Row>
          </Stack>
        ) : (
          <Button variant="outline" onClick={() => setShowAddForm(true)}>
            + Add Task
          </Button>
        )}
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state for tasks (updates from props + stream)
  const [localTasks, setLocalTasks] = useState(props.tasks || []);

  // Update local tasks when props change
  useEffect(() => {
    setLocalTasks(props.tasks || []);
  }, [props.tasks]);

  // Handle real-time task updates from stream
  useEffect(() => {
    if (!taskChanged.latest) return;

    const { action, task } = taskChanged.latest;
    if (!task) return;

    setLocalTasks((prev) => {
      if (action === 'create') {
        return [...prev, task];
      }
      if (action === 'delete') {
        return prev.filter((t) => t.id !== task.id);
      }
      // move, edit
      return prev.map((t) => (t.id === task.id ? { ...t, ...task } : t));
    });
  }, [taskChanged.latest]);

  // Handlers
  const handleMoveTask = useCallback(
    (taskId: string, columnId: string) => {
      setLocalTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: columnId } : t))
      );
      taskUpdate({ action: 'move', taskId, data: { column: columnId } });
    },
    [taskUpdate]
  );

  const handleEditTask = useCallback(
    (task: any) => {
      setLocalTasks((prev) =>
        prev.map((t) => (t.id === task.id ? task : t))
      );
      taskUpdate({ action: 'edit', taskId: task.id, data: { column: task.column, title: task.title, priority: task.priority, assignee: task.assignee, dueDate: task.dueDate } });
    },
    [taskUpdate]
  );

  const handleAddTask = useCallback(
    (title: string, priority: string) => {
      const newTask = {
        id: `task-${Date.now()}`,
        title,
        priority,
        column: props.columns[0]?.id || 'todo',
        assignee: '',
        dueDate: '',
      };
      setLocalTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: { column: newTask.column } });
    },
    [taskUpdate, props.columns]
  );

  // Compute stats
  const totalTasks = localTasks.length;
  const completedTasks = localTasks.filter((t) => t.column === 'done').length;

  return (
    <Container maxWidth="6xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Box
          padding="var(--ggui-spacing-4)"
          background="var(--ggui-color-primary-50)"
          borderRadius="var(--ggui-shape-radius-lg)"
        >
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-2)" direction="horizontal">
              <Heading level={3} color="var(--ggui-color-primary-900)">
                Task Board
              </Heading>
            </Stack>
            <Row gap="var(--ggui-spacing-4)" align="center">
              <Text variant="body" color="var(--ggui-color-primary-700)">
                <strong>{completedTasks}</strong> of <strong>{totalTasks}</strong> completed
              </Text>
              {totalTasks > 0 && (
                <Progress
                  value={completedTasks}
                  max={totalTasks}
                  variant="default"
                  size="md"
                  style={{ width: '120px' }}
                />
              )}
            </Row>
          </Row>
        </Box>

        {/* Kanban Board */}
        <Row
          gap="var(--ggui-spacing-4)"
          align="start"
          style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4)' }}
        >
          {props.columns && props.columns.length > 0
            ? props.columns.map((column) => (
              <KanbanColumn
                key={column.id}
                column={column}
                tasks={localTasks}
                columns={props.columns}
                onMove={handleMoveTask}
                onEdit={handleEditTask}
                onAddTask={(title, priority) => {
                  const newTask = {
                    id: `task-${Date.now()}-${Math.random()}`,
                    title,
                    priority,
                    column: 'todo',
                    assignee: '',
                    dueDate: '',
                  };
                  setLocalTasks((prev) => [...prev, newTask]);
                  taskUpdate({ action: 'create', taskId: newTask.id, data: { column: 'todo' } });
                }}
              />
            ))
            : null}
        </Row>
      </Stack>
    </Container>
  );
}

