          shadow="md"
          style={{
            flex: 1,
            overflowY: 'auto',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--ggui-spacing-4)',
          }}
        >
          {groupedMessages.length === 0 ? (
            <Box
              padding="var(--ggui-spacing-6)"
              style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                minHeight: '200px',
              }}
            >
              <Text color="var(--ggui-color-onSurfaceVariant)" align="center">
                No messages yet. Start the conversation!
              </Text>
            </Box>
          ) : (
            groupedMessages.map((group, groupIdx) => (
              <Stack key={groupIdx} gap="var(--ggui-spacing-2)">
                {group.messages.map((msg, msgIdx) => {
                  const isCurrentUser = group.sender === props.currentUser;
                  const isFirstInGroup = msgIdx === 0;

                  return (
                    <Stack
                      key={msgIdx}
                      direction="horizontal"
                      align="start"
                      justify={isCurrentUser ? 'end' : 'start'}
                      gap="var(--ggui-spacing-2)"
                    >
                      {!isCurrentUser && isFirstInGroup && (
                        <Avatar
                          name={group.sender}
                          size="sm"
                          style={{ marginTop: 'var(--ggui-spacing-1)', flexShrink: 0 }}
                        />
                      )}
                      {!isCurrentUser && !isFirstInGroup && (
                        <Box style={{ width: '32px', flexShrink: 0 }} />
                      )}

                      <Stack
                        gap="var(--ggui-spacing-1)"
                        style={{
                          maxWidth: '60%',
                          alignItems: isCurrentUser ? 'flex-end' : 'flex-start',
                        }}
                      >
                        {isFirstInGroup && !isCurrentUser && (
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                            {group.sender}
                          </Text>
                        )}
                        <Card
                          padding="var(--ggui-spacing-3)"
                          shadow="sm"
                          style={{
                            backgroundColor: isCurrentUser
