import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const MAX_COMMENTS = 500;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touchedName, setTouchedName] = useState<boolean>(false);
  const [touchedEmail, setTouchedEmail] = useState<boolean>(false);
  const [submitted, setSubmitted] = useState<boolean>(false);

  const totalSteps = 5;
  const progressValue = useMemo(() => (step / totalSteps) * 100, [step]);

  const nameError = useMemo(() => {
    if (!touchedName && !submitted) return '';
    if (!name.trim()) return 'Name is required.';
    return '';
  }, [name, touchedName, submitted]);

  const emailError = useMemo(() => {
    if (!touchedEmail && !submitted) return '';
    if (!email.trim()) return 'Email is required.';
    if (!EMAIL_REGEX.test(email.trim())) return 'Please enter a valid email address.';
    return '';
  }, [email, touchedEmail, submitted]);

  const isStepValid = useMemo(() => {
    if (step === 1) return !!name.trim() && EMAIL_REGEX.test(email.trim());
    if (step === 2) return !!satisfaction;
    if (step === 3) return true;
    if (step === 4) return comments.length <= MAX_COMMENTS;
    return true;
  }, [step, name, email, satisfaction, comments]);

  const handleFeatureToggle = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (step === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
    }
    if (!isStepValid) return;
    setStep((prev) => (prev < totalSteps ? prev + 1 : prev));
  }, [step, isStepValid]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    setSubmitted(true);
    if (!name.trim() || !EMAIL_REGEX.test(email.trim()) || !satisfaction) return;
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments,
    };
    submit(payload);
  }, [name, email, satisfaction, features, comments, submit]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" border radius="lg">
        <Stack gap="var(--ggui-spacing-5)">
          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center">
              <Heading level={3}>Survey Form</Heading>
              <Badge variant="primary">Step {step} of {totalSteps}</Badge>
            </Row>
            <Progress value={progressValue} max={100} variant="default" size="md" />
          </Stack>

          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Your Details</Heading>
              <Input
                label="Name"
                placeholder="Enter your name"
                value={name}
                onChange={(value) => setName(value)}
                required
                error={nameError || undefined}
                onBlur={() => setTouchedName(true)}
              />
              <Input
                label="Email"
                type="email"
                placeholder="you@example.com"
                value={email}
                onChange={(value) => setEmail(value)}
                required
                error={emailError || undefined}
                onBlur={() => setTouchedEmail(true)}
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you?"
                value={satisfaction}
                onChange={(value) => setSatisfaction(value)}
                options={(props.satisfactionLabels || []).map((label, index) => ({
                  value: String(index + 1),
                  label: `${index + 1} - ${label}`,
                }))}
                direction="vertical"
                error={submitted && !satisfaction ? 'Please select a satisfaction rating.' : undefined}
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Feature Interests</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">Select all features you are interested in.</Text>
              <Stack gap="var(--ggui-spacing-2)">
                {(props.featureOptions || []).map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={(checked) => handleFeatureToggle(feature, checked)}
                  />
                ))}
              </Stack>
              {(!props.featureOptions || props.featureOptions.length === 0) && (
                <Alert variant="info" title="No features available">
                  There are currently no feature options to choose from.
                </Alert>
              )}
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Additional Comments</Heading>
              <TextArea
                label="Comments (Optional)"
                placeholder="Share any additional feedback..."
                value={comments}
                onChange={(value) => setComments(value)}
                maxLength={MAX_COMMENTS}
                showCount
                rows={6}
                helperText="Maximum 500 characters"
              />
            </Stack>
          )}



          {step === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Review Your Answers</Heading>
              <Card padding="var(--ggui-spacing-4)" border shadow="none">
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between"><Text weight="medium">Name</Text><Text>{name || '—'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Row justify="between"><Text weight="medium">Email</Text><Text>{email || '—'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Row justify="between"><Text weight="medium">Satisfaction</Text><Text>{satisfaction ? `${satisfaction} - ${(props.satisfactionLabels || [])[Number(satisfaction) - 1] || ''}` : '—'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text weight="medium">Features</Text>
                    <Text color="var(--ggui-color-onSurfaceVariant)">{features.length ? features.join(', ') : 'None selected'}</Text>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text weight="medium">Comments</Text>
                    <Text color="var(--ggui-color-onSurfaceVariant)">{comments.trim() ? comments : 'No comments provided'}</Text>
                  </Stack>
                </Stack>
              </Card>
            </Stack>
          )}

          <Row justify="between" align="center">
            <Text color="var(--ggui-color-onSurfaceVariant)" variant="caption">
              {step < totalSteps ? 'Complete each step to continue.' : 'Review and submit your survey.'}
            </Text>
            <Row gap="var(--ggui-spacing-2)">
              {step > 1 && (
                <Button variant="outline" as={Clickable} onClick={handleBack}>
                  Back
                </Button>
              )}
              {step < totalSteps && (
                <Button variant="primary" as={Clickable} onClick={handleNext} disabled={!isStepValid}>
                  Next
                </Button>
              )}
              {step === totalSteps && (
                <Button variant="primary" as={Clickable} onClick={handleSubmit}>
                  Submit
                </Button>
              )}
            </Row>
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

