// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed

type BoardTask = {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  column: string;
  dueDate?: string;
};

function normalizeTask(task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }, fallbackColumn: string, index: number): BoardTask {
  return {
    id: task.id && task.id.length > 0 ? task.id : `task-${index}-${Date.now()}`,
    title: task.title && task.title.length > 0 ? task.title : 'Untitled task',
    priority: task.priority ?? 'medium',
    assignee: task.assignee && task.assignee.length > 0 ? task.assignee : 'NA',
    column: task.column && task.column.length > 0 ? task.column : fallbackColumn,
    dueDate: task.dueDate,
  };
}

function getPriorityVariant(priority: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' {
  if (priority === 'low') return 'success';
  if (priority === 'high') return 'error';
  return 'warning';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const firstColumnId = props.columns[0]?.id ?? 'todo';
  const [boardTasks, setBoardTasks] = useState<BoardTask[]>(() => (props.tasks ?? []).map((task, index) => normalizeTask(task, firstColumnId, index)));
  const [addingColumnId, setAddingColumnId] = useState<string>('');
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    setBoardTasks((props.tasks ?? []).map((task, index) => normalizeTask(task, firstColumnId, index)));
  }, [props.tasks, firstColumnId]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incoming = normalizeTask(taskChanged.latest.task, firstColumnId, boardTasks.length);

    setBoardTasks((prev) => {
      if (taskChanged.latest?.action === 'delete') {
        return prev.filter((task) => task.id !== incoming.id);
      }
      const existingIndex = prev.findIndex((task) => task.id === incoming.id);
      if (existingIndex >= 0) {
        const updated = [...prev];
        updated[existingIndex] = { ...updated[existingIndex], ...incoming };
        return updated;
      }
      return [...prev, incoming];
    });
  }, [taskChanged.latest, firstColumnId, boardTasks.length]);

  const totalTasks = boardTasks.length;
  const doneColumnId = (props.columns ?? []).find((col) => (col.name ?? '').toLowerCase() === 'done')?.id ?? 'done';
  const completedCount = boardTasks.filter((task) => task.column === doneColumnId).length;

  const moveTask = useCallback((taskId: string, targetColumn: string) => {
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: targetColumn } : task)));
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  }, [taskUpdate]);

  const saveEdit = useCallback((taskId: string) => {
    const nextTitle = editingTitle.trim();
    if (!nextTitle) return;
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: nextTitle } : task)));
    setEditingTaskId('');
    setEditingTitle('');
    const currentTask = boardTasks.find((task) => task.id === taskId);
    taskUpdate({ action: 'edit', taskId, data: { column: currentTask?.column ?? firstColumnId } });
  }, [editingTitle, taskUpdate, boardTasks, firstColumnId]);

  const createTask = useCallback((columnId: string) => {
    const trimmed = newTaskTitle.trim();
    if (!trimmed) return;
    const id = `task-${Date.now()}`;
    const task: BoardTask = { id, title: trimmed, priority: newTaskPriority, assignee: 'NA', column: columnId };
    setBoardTasks((prev) => [...prev, task]);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingColumnId('');
    taskUpdate({ action: 'create', taskId: id, data: { column: columnId } });
  }, [newTaskTitle, newTaskPriority, taskUpdate]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center">
            <Heading level={3}>Task Board Summary</Heading>
            <Row gap="var(--ggui-spacing-2)">
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
        </Card>

        {(props.columns ?? []).length === 0 ? (
          <Alert variant="warning" title="No columns configured">Add board columns to get started.</Alert>
        ) : (
          <Row gap="var(--ggui-spacing-4)" align="start" wrap>
            {(props.columns ?? []).map((column, columnIndex) => {
              const columnId = column.id ?? `column-${columnIndex}`;
              const columnTasks = boardTasks.filter((task) => task.column === columnId);
              return (
                <Card key={columnId} padding="var(--ggui-spacing-4)" shadow="sm" border>
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between" align="center">
                      <Heading level={4}>{column.name ?? 'Unnamed'}</Heading>
                      <Badge variant="default">{columnTasks.length}</Badge>
                    </Row>

                    <Stack gap="var(--ggui-spacing-2)">
                      {columnTasks.length === 0 ? (
                        <Text color="var(--ggui-color-onSurfaceVariant)">No tasks yet.</Text>
                      ) : (
                        columnTasks.map((task) => (
                          <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="none" border>
                            <Stack gap="var(--ggui-spacing-2)">
                              <Row justify="between" align="center">
                                {editingTaskId === task.id ? (
                                  <Input label="Edit task title" value={editingTitle} onChange={setEditingTitle} />
                                ) : (
                                  <Text
                                    as={Clickable}
                                    onClick={() => { setEditingTaskId(task.id); setEditingTitle(task.title); }}
                                    onDoubleClick={() => { setEditingTaskId(task.id); setEditingTitle(task.title); }}
                                    onKeyDown={(event) => {
                                      if (event.key === 'Enter' || event.key === ' ') {
                                        event.preventDefault();
                                        setEditingTaskId(task.id);
                                        setEditingTitle(task.title);
                                      }
                                    }}
                                    hoverStyle={{ color: 'var(--ggui-color-primary-700)', textDecoration: 'underline' }}
                                    style={{ outlineOffset: '2px' }}
                                    weight="medium"
                                  >
                                    {task.title}
                                  </Text>
                                )}
                                <Badge variant={getPriorityVariant(task.priority)}>{task.priority}</Badge>
                              </Row>

                              <Row justify="between" align="center">
                                <Row gap="var(--ggui-spacing-2)" align="center">
                                  <Avatar name={task.assignee} size="sm" />
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{task.assignee}</Text>
                                </Row>
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  {task.dueDate ? `Due: ${task.dueDate}` : 'No due date'}
                                </Text>
                              </Row>

                              <Select
                                label="Move task"
                                value={task.column}
                                onChange={(value) => moveTask(task.id, value)}
                                options={(props.columns ?? []).map((c, i) => ({ value: c.id ?? `column-${i}`, label: c.name ?? 'Unnamed' }))}
                              />

                              <Row gap="var(--ggui-spacing-2)">
                                {editingTaskId === task.id ? (
                                  <>
                                    <Button variant="primary" size="sm" onClick={() => saveEdit(task.id)}>Save</Button>
                                    <Button variant="ghost" size="sm" onClick={() => { setEditingTaskId(''); setEditingTitle(''); }}>Cancel</Button>
                                  </>
                                ) : (
                                  <Button variant="outline" size="sm" onClick={() => { setEditingTaskId(task.id); setEditingTitle(task.title); }}>Edit</Button>
                                )}
                              </Row>
                            </Stack>
                          </Card>
                        ))
                      )}
                    </Stack>

                    {addingColumnId === columnId ? (
                      <Card padding="var(--ggui-spacing-3)" shadow="none" border>
                        <Stack gap="var(--ggui-spacing-2)">
                          <Input label="Task title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Enter task title" />
                          <Select
                            label="Priority"
                            value={newTaskPriority}
                            onChange={(value) => setNewTaskPriority((value as 'low' | 'medium' | 'high') || 'medium')}
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' },
                            ]}
                          />
                          <Row gap="var(--ggui-spacing-2)">
                            <Button variant="primary" size="sm" onClick={() => createTask(columnId)}>Create</Button>
                            <Button variant="ghost" size="sm" onClick={() => setAddingColumnId('')}>Cancel</Button>
                          </Row>
                        </Stack>
                      </Card>
                    ) : (
                      <Button variant="secondary" fullWidth onClick={() => setAddingColumnId(columnId)}>Add Task</Button>
                    )}
                  </Stack>
                </Card>
              );
            })}
          </Row>
        )}
      </Stack>
    </Container>

  );
}

