import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





// Place helper components here if needed
const CATEGORY_COLORS: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-100)',
  'alkaline earth metal': 'var(--ggui-color-warning-100)',
  'transition metal': 'var(--ggui-color-primary-100)',
  'post-transition metal': 'var(--ggui-color-info-100)',
  metalloid: 'var(--ggui-color-success-100)',
  nonmetal: 'var(--ggui-color-surfaceVariant)',
  halogen: 'var(--ggui-color-warning-50)',
  'noble gas': 'var(--ggui-color-primary-50)',
  lanthanide: 'var(--ggui-color-success-50)',
  actinide: 'var(--ggui-color-error-50)',
  unknown: 'var(--ggui-color-surfaceVariant)',
};

function normalizeCategory(category?: string): string {
  if (!category) return 'unknown';
  return category.trim().toLowerCase().replace(/[-_]+/g, ' ');
}

function getCategoryColor(category?: string): string {
  const normalized = normalizeCategory(category);
  return CATEGORY_COLORS[normalized] || 'var(--ggui-color-surfaceVariant)';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [query, setQuery] = useState<string>('');
  const [selectedElementAtomicNumber, setSelectedElementAtomicNumber] = useState<number | null>(null);

  const safeElements = useMemo(() => {
    return Array.isArray(props.elements) ? props.elements : [];
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const normalizedQuery = query.trim().toLowerCase();
    if (!normalizedQuery) return safeElements;
    return safeElements.filter((element) => {
      const nameMatches = (element.name || '').toLowerCase().includes(normalizedQuery);
      const symbolMatches = (element.symbol || '').toLowerCase().includes(normalizedQuery);
      return nameMatches || symbolMatches;
    });
  }, [safeElements, query]);

  const selectedElement = useMemo(() => {
    if (selectedElementAtomicNumber === null) return null;
    return safeElements.find((element) => element.atomicNumber === selectedElementAtomicNumber) || null;
  }, [safeElements, selectedElementAtomicNumber]);

  const categories = useMemo(() => {
    const allCategories = safeElements.map((element) => normalizeCategory(element.category));
    return Array.from(new Set(allCategories)).sort((a, b) => a.localeCompare(b));
  }, [safeElements]);

  useEffect(() => {
    if (!filteredElements.length) {
      setSelectedElementAtomicNumber(null);
      return;
    }
    const stillVisible = filteredElements.some((element) => element.atomicNumber === selectedElementAtomicNumber);
    if (!stillVisible) {
      setSelectedElementAtomicNumber(filteredElements[0].atomicNumber ?? null);
    }
  }, [filteredElements, selectedElementAtomicNumber]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>Interactive Periodic Table</Heading>
          <Text color="var(--ggui-color-onSurfaceVariant)">
            Search by element name or symbol, then select an element to view detailed information.
          </Text>
        </Stack>

        <Input
          label="Search elements"
          placeholder="Type name or symbol (e.g., Oxygen or O)"
          value={query}
          onChange={setQuery}
        />

        {safeElements.length === 0 ? (
          <Alert variant="warning" title="No element data">
            No periodic table data is available in props.elements.
          </Alert>
        ) : (
          <Card padding="var(--ggui-spacing-4)">
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                gap: 'var(--ggui-spacing-2)',
                overflowX: 'auto',
              }}
            >
              {filteredElements.map((element, index) => {
                const cellKey = `${element.atomicNumber || 'na'}-${element.symbol || 'unknown'}-${index}`;
                const isSelected = element.atomicNumber === selectedElementAtomicNumber;
                return (
                  <Card
                    key={cellKey}
                    as={Clickable}
                    onClick={() => setSelectedElementAtomicNumber(element.atomicNumber ?? null)}
                    padding="var(--ggui-spacing-2)"
                    border
                    radius="md"
                    shadow="none"
                    style={{
                      gridColumn: `${element.col || 1} / span 1`,
                      gridRow: `${element.row || 1} / span 1`,
                      minHeight: '72px',
                      background: getCategoryColor(element.category),
                      borderColor: isSelected ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                      borderWidth: isSelected ? '2px' : '1px',
                      borderStyle: 'solid',
                      position: 'relative',
                    }}
                  >
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant)"
                      style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                    >
                      {element.atomicNumber ?? '-'}
                    </Text>
                    <Row justify="center" align="center" style={{ height: '100%' }}>
                      <Text size="xl" weight="bold" align="center">
                        {element.symbol || '?'}
                      </Text>
                    </Row>
                  </Card>
                );
              })}
            </Box>
          </Card>
        )}

        {safeElements.length > 0 && filteredElements.length === 0 && (
          <Alert variant="info" title="No matches">
            No elements match your search. Try another name or symbol.
          </Alert>
        )}

        <Card padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-2)">
                <Text><Text is="span" weight="semibold">Name:</Text> {selectedElement.name || '-'}</Text>
                <Text><Text is="span" weight="semibold">Symbol:</Text> {selectedElement.symbol || '-'}</Text>
                <Text><Text is="span" weight="semibold">Atomic Number:</Text> {selectedElement.atomicNumber ?? '-'}</Text>
                <Text><Text is="span" weight="semibold">Atomic Weight:</Text> {selectedElement.atomicWeight ?? '-'}</Text>
                <Text><Text is="span" weight="semibold">Category:</Text> {selectedElement.category || '-'}</Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant)">Select an element to view details.</Text>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Legend</Heading>
            <Row wrap gap="var(--ggui-spacing-2)">
              {categories.map((category) => (
                <Row key={category} align="center" gap="var(--ggui-spacing-2)">
                  <Box
                    style={{
                      width: '14px',
                      height: '14px',
                      borderRadius: 'var(--ggui-shape-radius-sm)',
                      background: getCategoryColor(category),
                      border: '1px solid var(--ggui-color-outline)',
                    }}
                  />
                  <Text variant="bodySmall">{category}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

