function renderStars(ratingValue: number) {
  const normalized = Math.max(0, Math.min(5, Math.round(ratingValue)));
  const stars: React.ReactNode[] = [];
  for (let i = 1; i <= 5; i += 1) {
    stars.push(
      <Text key={i} is="span" color={i <= normalized ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}>
        {i <= normalized ? '★' : '☆'}
      </Text>
    );
  }
  return stars;
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
