    const currencySymbol = props.product.currency ?? '$';
    return `${currencySymbol}${priceValue.toFixed(2)}`;
  }, [props.product.price, props.product.currency]);

  const specificationRows = useMemo(() => {
    const specs = Array.isArray(props.product.specifications) ? props.product.specifications : [];
    return specs as ProductSpecification[];
  }, [props.product.specifications]);

  const reviewRows = useMemo(() => {
    const reviews = Array.isArray(props.product.reviews) ? props.product.reviews : [];
    return reviews as ProductReview[];
  }, [props.product.reviews]);

  useEffect(() => {
    if (isOutOfStock) {
      setQuantity(1);
      return;
    }
    if (quantity > maxQuantity) {
      setQuantity(maxQuantity);
    }
    if (quantity < 1) {
