                Real-time chat
              </Text>
            </Stack>
            <Badge variant="primary">{props.participantCount} participants</Badge>
          </Row>

          {formattedTypingText ? (
            <Box
              padding="var(--ggui-spacing-2)"
              background="var(--ggui-color-surfaceVariant)"
              borderRadius="var(--ggui-shape-radius-md)"
            >
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {formattedTypingText}
              </Text>
            </Box>
          ) : null}

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Stack gap="var(--ggui-spacing-3)">
              <Box
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-md)"
                padding="var(--ggui-spacing-2)"
                style={{ height: '55vh', overflowY: 'auto' }}
              >
                <Stack gap="var(--ggui-spacing-2)">
                  {groupedMessages.length === 0 ? (
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      No messages yet.
                    </Text>
                  ) : (
                    groupedMessages.map((group, groupIndex) => {
                      const isCurrentUser = group.sender === props.currentUser;
                      return (
                        <Stack
                          key={`${group.sender || 'unknown'}-${groupIndex}`}
                          gap="var(--ggui-spacing-1)"
                          align={isCurrentUser ? 'end' : 'start'}
                        >
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {group.sender || 'Unknown'}
                          </Text>
                          {group.items.map((msg, msgIndex) => (
                            <Box
                              key={`${groupIndex}-${msgIndex}-${msg.timestamp || ''}`}
                              padding="var(--ggui-spacing-2)"
                              background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                              borderRadius="var(--ggui-shape-radius-md)"
                            >
                              <Stack gap="var(--ggui-spacing-1)">
                                <Text
                                  variant="bodySmall"
                                  color={isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                                >
                                  {msg.text || ''}
                                </Text>
                                <Text
                                  variant="caption"
                                  color={isCurrentUser ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                                  align={isCurrentUser ? 'right' : 'left'}
                                >
                                  {formatTimestamp(msg.timestamp)}
                                </Text>
                              </Stack>
                            </Box>
                          ))}
                        </Stack>
                      );
                    })
                  )}
                  <Box><div ref={messagesEndRef} /></Box>
                </Stack>
              </Box>

              <Row gap="var(--ggui-spacing-2)" align="end">
                <Box style={{ flex: 1 }}>
                  <Input
                    label="Message"
                    placeholder="Type a message..."
                    value={draft}
                    onChange={setDraft}
                    onKeyDown={(event) => {
                      if (event.key === 'Enter' && !event.shiftKey) {
                        event.preventDefault();
                        handleSend();
                      }
                    }}
                  />
                </Box>
                <Button
                  variant="primary"
                  disabled={!draft.trim()}
                  onClick={handleSend}
                >
                  Send
                </Button>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>

  );
}

