interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Place helper components here if needed
const formatPrice = (value?: number): string => `$${(value ?? 0).toFixed(2)}`;
const formatSigned = (value?: number): string => {
  const amount = value ?? 0;
  const sign = amount > 0 ? '+' : '';
  return `${sign}${amount.toFixed(2)}`;
};
const formatPercent = (value?: number): string => {
  const amount = value ?? 0;
  const sign = amount > 0 ? '+' : '';
  return `${sign}${amount.toFixed(2)}%`;
};

const getChangeColor = (value?: number): string => {
  if ((value ?? 0) >= 0) {
    return 'var(--ggui-color-success-600)';
  }
  return 'var(--ggui-color-error-600)';
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  const [stocks, setStocks] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<string>(new Date().toLocaleTimeString());
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});

  useEffect(() => {
    setStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setLastUpdated(new Date().toLocaleTimeString());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest?.symbol) {
      return;
    }

    setStocks((prev) => {
      const symbol = priceUpdate.latest?.symbol;
      if (!symbol) {
        return prev;
      }

      let found = false;
      const updated = prev.map((stock) => {
        if (stock.symbol === symbol) {
          found = true;
          return {
            ...stock,
            price: priceUpdate.latest?.price ?? stock.price,
            change: priceUpdate.latest?.change ?? stock.change,
            changePercent: priceUpdate.latest?.changePercent ?? stock.changePercent,
          };
        }
        return stock;
      });

      if (!found) {
        updated.push({
          symbol: priceUpdate.latest?.symbol,
          name: priceUpdate.latest?.symbol,
          price: priceUpdate.latest?.price,
          change: priceUpdate.latest?.change,
          changePercent: priceUpdate.latest?.changePercent,
        });
      }

      return updated;
    });

    setLastUpdated(new Date().toLocaleTimeString());
    setFlashMap((prev) => ({ ...prev, [priceUpdate.latest.symbol as string]: Date.now() }));
  }, [priceUpdate.latest]);

  useEffect(() => {
    if (marketStatus.latest?.timestamp) {
      setLastUpdated(new Date(marketStatus.latest.timestamp).toLocaleTimeString());
    }
  }, [marketStatus.latest]);

  useEffect(() => {
    const keys = Object.keys(flashMap);
    if (keys.length === 0) {
      return;
    }
    const timeout = setTimeout(() => {
      setFlashMap((prev) => {
        const next: Record<string, number> = {};
        Object.keys(prev).forEach((key) => {
          if (Date.now() - prev[key] < 700) {
            next[key] = prev[key];
          }
        });
        return next;
      });
    }, 750);
    return () => clearTimeout(timeout);
  }, [flashMap]);

  const marketStatusText = marketStatus.latest?.status ?? 'open';
  const statusVariant = marketStatusText === 'open' ? 'success' : marketStatusText === 'closed' ? 'error' : 'warning';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Row justify="between" align="center" wrap>
          <Stack gap="var(--ggui-spacing-1)">
            <Heading level={1} color="var(--ggui-color-onSurface)">
              Market Watch
            </Heading>
            <Row gap="var(--ggui-spacing-2)" align="center" wrap>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated: {lastUpdated}
              </Text>
              <Badge variant={statusVariant}>
                {marketStatusText}
              </Badge>
            </Row>
          </Stack>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Stream events: {priceUpdate.all.length}
          </Text>
        </Row>

        {stocks.length === 0 ? (
          <Card padding="var(--ggui-spacing-6)" shadow="sm">
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                No stocks available.
              </Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Waiting for live updates...
              </Text>
            </Stack>
          </Card>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stocks.map((stock, index) => {
              const isPositive = (stock.change ?? 0) >= 0;
              const directionArrow = isPositive ? '▲' : '▼';
              const color = getChangeColor(stock.change);
              const flashActive = stock.symbol ? Boolean(flashMap[stock.symbol]) : false;

              return (
                <Card
                  key={`${stock.symbol ?? 'stock'}-${index}-${flashMap[stock.symbol ?? ''] ?? 0}`}
>
                  <Box
                    padding="var(--ggui-spacing-4)"
                    background={flashActive ? 'var(--ggui-color-primary-100)' : 'transparent'}
                    borderRadius="var(--ggui-shape-radius-md)"
                  >
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
                        {stock.symbol ?? 'N/A'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name ?? 'Unknown Company'}
                      </Text>

                      <Divider margin="var(--ggui-spacing-2)" />

                      <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">
                        {formatPrice(stock.price)}
                      </Text>
                      <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                        <Text variant="body" weight="medium" color={color}>
                          {formatSigned(stock.change)}
                        </Text>
                        <Text variant="body" weight="medium" color={color}>
                          {directionArrow} {formatPercent(stock.changePercent)}
                        </Text>
                      </Row>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>

  );
}

