import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





const DEFAULT_AVATARS = ['😀', '😎', '🚀', '🌟'];
const DEFAULT_ROLES = ['Developer', 'Designer', 'Manager', 'Other'];

const isValidEmail = (value: string) => {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(value.trim());
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile?.avatar ?? '');
  const [role, setRole] = useState(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile?.theme === 'dark' ? 'dark' : 'light');
  const [hasTriedNext, setHasTriedNext] = useState(false);

  const avatarChoices = useMemo(() => {
    if (props.avatarOptions && props.avatarOptions.length > 0) {
      return props.avatarOptions.slice(0, 4);
    }
    return DEFAULT_AVATARS;
  }, [props.avatarOptions]);

  const roleChoices = useMemo(() => {
    if (props.roleOptions && props.roleOptions.length > 0) {
      return props.roleOptions;
    }
    return DEFAULT_ROLES;
  }, [props.roleOptions]);

  useEffect(() => {
    if (!avatar && avatarChoices.length > 0) {
      setAvatar(avatarChoices[0]);
    }
  }, [avatar, avatarChoices]);

  useEffect(() => {
    if (!role && roleChoices.length > 0) {
      setRole(roleChoices[0]);
    }
  }, [role, roleChoices]);

  const nameError = useMemo(() => {
    if (!hasTriedNext) {
      return '';
    }
    return name.trim() ? '' : 'Name is required';
  }, [name, hasTriedNext]);

  const emailError = useMemo(() => {
    if (!hasTriedNext) {
      return '';
    }
    if (!email.trim()) {
      return 'Email is required';
    }
    if (!isValidEmail(email)) {
      return 'Please enter a valid email address';
    }
    return '';
  }, [email, hasTriedNext]);

  const isStep1Valid = useMemo(() => {
    return name.trim().length > 0 && isValidEmail(email) && avatar.trim().length > 0;
  }, [name, email, avatar]);

  const isStep2Valid = useMemo(() => {
    return role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  }, [role, theme]);

  const canGoNext = useMemo(() => {
    if (step === 1) {
      return isStep1Valid;
    }
    if (step === 2) {
      return isStep2Valid;
    }
    return true;
  }, [step, isStep1Valid, isStep2Valid]);

  const progressValue = useMemo(() => {
    return Math.round((step / 3) * 100);
  }, [step]);

  const goNext = useCallback(() => {
    if (step === 1 && !isStep1Valid) {
      setHasTriedNext(true);
      return;
    }
    if (step === 2 && !isStep2Valid) {
      return;
    }
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [step, isStep1Valid, isStep2Valid]);

  const goBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleComplete = useCallback(() => {
    if (!isStep1Valid || !isStep2Valid) {
      return;
    }
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    (props as Props & { onComplete?: (data: ActionCompletePayload) => void }).onComplete?.(payload);

  }, [name, email, avatar, role, emailNotifications, theme, isStep1Valid, isStep2Valid, props]);
  const stepHeadingRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (stepHeadingRef.current) {
      stepHeadingRef.current.focus();
    }
  }, [step]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-4">
            <Row justify="between" align="center">
              <Stack gap="var(--ggui-spacing-1)">
                <Heading level={2}>Onboarding Wizard</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Step {step} of 3
                </Text>
              </Stack>
              <Badge variant="primary">{progressValue}%</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" variant="default" />
            <Box is="ol" style={{ margin: 0, paddingLeft: 'var(--ggui-spacing-4)' }}>
              <Row gap="var(--ggui-spacing-2)" wrap>
                <Text is="span" aria-current={step === 1 ? 'step' : undefined}><Badge variant={step >= 1 ? 'primary' : 'default'}>1. Profile Setup</Badge></Text>
                <Text is="span" aria-current={step === 2 ? 'step' : undefined}><Badge variant={step >= 2 ? 'primary' : 'default'}>2. Preferences</Badge></Text>
                <Text is="span" aria-current={step === 3 ? 'step' : undefined}><Badge variant={step >= 3 ? 'primary' : 'default'}>3. Review &amp; Confirm</Badge></Text>
              </Row>
            </Box>
          </Stack>
        </Card>


        <Card
          padding="var(--ggui-spacing-6)"
          shadow="md"
          radius="lg"
        >
          <Box
            key={step}
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
              transition: 'all 200ms ease-in-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Box tabIndex={-1} ref={stepHeadingRef as React.RefObject<HTMLDivElement>}><Heading level={3}>Profile Setup</Heading></Box>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your full name"
                  required
                  error={nameError}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={emailError}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" is="label" id="avatar-group-label">Choose Avatar</Text>
                  <RadioGroup
                    label="Choose Avatar"
                    value={avatar}
                    onChange={setAvatar}
                    options={avatarChoices.map((option) => ({ value: option, label: option }))}
                    direction="horizontal"
                  />
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Box tabIndex={-1} ref={stepHeadingRef as React.RefObject<HTMLDivElement>}><Heading level={3}>Preferences</Heading></Box>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={roleChoices.map((option) => ({ value: option, label: option }))}
                  placeholder="Select a role"
                  required
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Row align="center" justify="between">
                  <Text variant="label">Theme preference</Text>
                  <Toggle
                    label={theme === 'dark' ? 'Dark mode' : 'Light mode'}
                    checked={theme === 'dark'}
                    onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  />
                </Row>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Box tabIndex={-1} ref={stepHeadingRef as React.RefObject<HTMLDivElement>}><Heading level={3}>Review &amp; Confirm</Heading></Box>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Please review your details before completing setup.
                </Text>
                <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-4)" />

          <Row justify="between" align="center">
            <Button variant="ghost" onClick={goBack} disabled={step === 1}>
              Back
            </Button>
            {step < 3 ? (
              <Button variant="primary" onClick={goNext} disabled={!canGoNext}>
                Next
              </Button>
            ) : (
              <Row gap="var(--ggui-spacing-2)">
                <Button variant="outline" onClick={goBack}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={handleComplete}>
                  Complete Setup
                </Button>
              </Row>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
